{
 "level": "B1",
 "intro": "In this topic, you will learn in detail <strong>Future Simple Passive</strong>: how to form affirmatives, negatives and questions, when to use this form and what common mistakes to avoid.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>Subject + will be + V3 (Past Participle)</strong>:",
 "example": "The letter will be sent tomorrow."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>Subject + will not (won't) be + V3</strong>:",
 "example": "The letter will not be sent today."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Will + Subject + be + V3?</strong>:",
 "example": "Will the letter be sent on time?"
 }
 ]
}

{
 "title": "1. Structure of the Future Simple Passive",
 "intro": "<strong>Will</strong> is the same for all persons, and <strong>be</strong> remains unchanged:",
 "items": [
 {
 "label": "All persons",
 "title": "will be + V3",
 "subtitle": "I/You/He/She/It/We/They will be invited."
 },
 {
 "label": "Singular",
 "title": "will be + V3",
 "subtitle": "The report will be submitted. - A report will be submitted."
 },
 {
 "label": "Plural",
 "title": "will be + V3",
 "subtitle": "All tasks will be completed. - All tasks will be completed."
 },
 {
 "label": "Key",
 "title": "will be is an invariant part",
 "subtitle": "will be always comes before V3."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Word order: <strong>Subject + will be + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The results will be announced tomorrow.",
 "ua": "The results will be announced tomorrow."
 },
 {
 "en": "The meeting will be held next Monday.",
 "ua": "The meeting will be held next Monday."
 },
 {
 "en": "You will be contacted soon.",
 "ua": "You will be contacted soon."
 },
 {
 "en": "The project will be completed by the team.",
 "ua": "The project will be completed by the team."
 }
 ]
 },
 {
 "label": "With the instructions of the performer",
 "color": "sky",
 "description": "When it is important to specify <strong>who will perform the action</strong>:",
 "examples": [
 {
 "en": "The decision will be made by the board.",
 "ua": "The decision will be made by the board."
 },
 {
 "en": "The cake will be baked by my mother.",
 "ua": "The cake will be baked by my mother."
 },
 {
 "en": "The email will be sent by the secretary.",
 "ua": "The email will be sent by the secretary."
 }
 ]
 }
 ]
}

{
 "title": "3. When to use Future Simple Passive?",
 "sections": [
 {
 "label": "Plans and forecasts",
 "color": "emerald",
 "description": "For actions that <strong>occur in the future</strong>:",
 "examples": [
 {
 "en": "The new bridge will be built next year.",
 "ua": "The new bridge will be built next year."
 },
 {
 "en": "The package will be delivered tomorrow.",
 "ua": "The package will be delivered tomorrow."
 },
 {
 "en": "The guests will be welcomed at the entrance.",
 "ua": "The guests will be welcomed at the entrance."
 }
 ]
 },
 {
 "label": "Official announcements",
 "color": "blue",
 "description": "In <strong>official messages and announcements</strong>:",
 "examples": [
 {
 "en": "The winner will be announced at 5 PM.",
 "ua": "The winner will be announced at 5 PM."
 },
 {
 "en": "All applicants will be notified by email.",
 "ua": "All applicants will be notified by email."
 },
 {
 "en": "The office will be closed for renovation.",
 "ua": "The office will be closed for renovation."
 }
 ]
 },
 {
 "label": "Promises and assurances",
 "color": "amber",
 "description": "For <strong>promises</strong> and <strong>assurances</strong>:",
 "examples": [
 {
 "en": "Your complaint will be addressed immediately.",
 "ua": "Your complaint will be addressed immediately."
 },
 {
 "en": "You will be given a full refund.",
 "ua": "You will be given a full refund."
 },
 {
 "en": "The problem will be solved as soon as possible.",
 "ua": "The problem will be solved as soon as possible."
 }
 ]
 }
 ]
}

{
 "title": "4. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after will: <strong>Subject + will not (won't) be + V3</strong>",
 "examples": [
 {
 "en": "The project will not be finished on time.",
 "ua": "The project will not be finished on time."
 },
 {
 "en": "The documents will not be signed today.",
 "ua": "The documents will not be signed today."
 },
 {
 "en": "The meeting will not be held tomorrow.",
 "ua": "The meeting will not be held tomorrow."
 },
 {
 "en": "You will not be charged for this service.",
 "ua": "You will not be charged for this service."
 }
 ]
 },
 {
 "label": "Abbreviated form",
 "color": "amber",
 "description": "Colloquially: <strong>won't be</strong>",
 "examples": [
 {
 "en": "The email won't be sent until Monday.",
 "ua": "The email won't be sent until Monday."
 },
 {
 "en": "The tickets won't be available online.",
 "ua": "The tickets won't be available online."
 },
 {
 "en": "The decision won't be made today.",
 "ua": "The decision won't be made today."
 }
 ]
 }
 ]
}

{
 "title": "5. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Will</strong> comes first: <strong>Will + Subject + be + V3?</strong>",
 "examples": [
 {
 "en": "Will the report be ready by Friday?",
 "ua": "Will the report be ready by Friday?"
 },
 {
 "en": "Will the meeting be held online?",
 "ua": "Will the meeting be held online?"
 },
 {
 "en": "Will we be informed about the changes?",
 "ua": "Will we be informed about the changes?"
 },
 {
 "en": "Will the package be delivered tomorrow?",
 "ua": "Will the package be delivered tomorrow?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + will + Subject + be + V3?</strong>",
 "examples": [
 {
 "en": "When will the results be announced?",
 "ua": "When will the results be announced?"
 },
 {
 "en": "Where will the event be held?",
 "ua": "Where will the event be held?"
 },
 {
 "en": "How will the problem be solved?",
 "ua": "How will the problem be solved?"
 },
 {
 "en": "Why will the office be closed?",
 "ua": "Why will the office be closed?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + pronoun + will (not)</strong>:",
 "examples": [
 {
 "en": "Will the email be sent? — Yes, it will. / No, it won't.",
 "ua": "Will the email be sent? — Yes, it will. / No, it won't."
 },
 {
 "en": "Will they be invited? — Yes, they will. / No, they won't.",
 "ua": "Will they be invited? — Yes, they will. / No, they won't."
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison of Active vs Passive in Future Simple",
 "intro": "How to turn an active sentence into a passive:",
 "rows": [
 {
 "en": "Active: They will send the letter tomorrow.",
 "ua": "Active: They will send the letter tomorrow.",
 "note": "→ Passive: The letter will be sent tomorrow."
 },
 {
 "en": "Active: The company will hire new staff.",
 "ua": "Active: The company will hire new staff.",
 "note": "→ Passive: New staff will be hired."
 },
 {
 "en": "Active: Someone will repair the car.",
 "ua": "Active: Someone will repair the car.",
 "note": "→ Passive: The car will be repaired."
 },
 {
 "en": "Active: We will hold the meeting next week.",
 "ua": "Active: We will hold the meeting next week.",
 "note": "→ Passive: The meeting will be held next week."
 }
 ],
 "warning": "📌 Time markers (tomorrow, next week, soon) remain!"
}

{
 "title": "7. Time markers for the Future Simple Passive",
 "intro": "Typical words and expressions indicating the Future Simple:",
 "items": [
 {
 "label": "Tomorrow",
 "title": "tomorrow, the day after tomorrow",
 "subtitle": "The report will be submitted tomorrow."
 },
 {
 "label": "Following",
 "title": "next week/month/year",
 "subtitle": "The project will be completed next month."
 },
 {
 "label": "Soon",
 "title": "soon, shortly, in a few days",
 "subtitle": "You will be contacted soon."
 },
 {
 "label": "Specific time",
 "title": "at 5 PM, on Monday, in 2025",
 "subtitle": "The results will be announced at 5 PM."
 }
 ]
}

{
 "title": "8. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Skip be.",
 "wrong": "The letter will sent tomorrow.",
 "right": "✅ The letter will be sent tomorrow."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using V1 instead of V3.",
 "wrong": "The report will be write.",
 "right": "✅ The report will be written."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "The word order in the question is incorrect.",
 "wrong": "Will be the meeting held?",
 "right": "✅ Will the meeting be held?"
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Double will.",
 "wrong": "The project will will be completed.",
 "right": "✅ The project will be completed."
 }
 ]
}
